if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const row = $input.first().json || {};
let incumbent = null;
try { incumbent = row.incumbent_analysis ? JSON.parse(row.incumbent_analysis) : null; } catch(e) { incumbent = row.incumbent_analysis; }
return [{ json: {
  status: 'ok',
  module: 'incumbent_analysis',
  opp_id: row.id,
  solicitation_number: row.solicitation_number,
  opp_title: row.opp_title,
  agency: row.agency,
  naics_code: row.naics_code,
  set_aside: row.set_aside,
  gda_score: row.gda_score,
  gda_label: row.gda_label,
  govtribe_id: row.govtribe_id,
  estimated_value: row.estimated_value,
  incumbent_data: incumbent,
  has_data: !!incumbent,
  enrichment_hint: !incumbent ? { agency: row.agency, naics: row.naics_code, set_aside: row.set_aside, govtribe_id: row.govtribe_id, instruction: 'Call GovTribe Search_Federal_Contract_Awards with this agency + NAICS to find incumbents, then POST back to action=enrich' } : null
} }];

// Batch enrichment - build individual UPDATE statements
const body = $input.first().json.body || $input.first().json;
const records = body.records || [];
if (!records.length) return [{ json: { _empty: true, status: 'error', message: 'No records' } }];
const results = [];
for (const r of records) {
  const incumbentJson = JSON.stringify(r.incumbent_data).replace(/'/g, "''");
  results.push({ json: {
    solicitation_number: r.solicitation_number,
    incumbent_json: incumbentJson,
    _empty: false
  }});
}
return results;

const row = $input.first().json || {};
// Infer request body from upstream Query node context
const contract_number = '';
const vendor_name = '';
const agency = row.agency || '';

if (row.incumbent_analysis) {
  let incumbents = row.incumbent_analysis;
  if (typeof incumbents === 'string') {
    try { incumbents = JSON.parse(incumbents); } catch(e) {}
  }
  return [{json: {
    status: 'ok',
    source: 'database',
    contract_number: row.solicitation_number,
    vendor_name: vendor_name,
    agency: row.agency,
    opp_title: row.opp_title,
    gda_score: row.gda_score,
    gda_label: row.gda_label,
    estimated_value: row.estimated_value,
    incumbent_data: incumbents,
    generated_at: new Date().toISOString()
  }}];
}

const prompt = `You are a defense contract incumbent analysis expert for Georgetown Defense Analytics (GDA). Analyze this incumbent situation and identify displacement opportunities.

OPPORTUNITY: ${row.opp_title || 'Unknown'}
AGENCY: ${row.agency || agency}
NAICS: ${row.naics_code || ''}
ESTIMATED VALUE: $${parseInt(row.estimated_value||0).toLocaleString()}
GDA SCORE: ${row.gda_score || 0} (${row.gda_label || 'Unknown'})

Identify likely incumbent contractors and assess EIS displacement opportunity.

Return ONLY this JSON:
{"opp_title":"${(row.opp_title||'').replace(/"/g,"'")}","agency":"${(row.agency||'').replace(/"/g,"'")}","likely_incumbents":[{"name":"","rationale":"","threat_level":"HIGH/MEDIUM/LOW"}],"weakness_assessment":["weakness1","weakness2"],"displacement_strategy":"EIS approach","win_themes":["theme1","theme2"],"risk_factors":["risk1"],"capture_recommendation":"next step","confidence":"HIGH/MEDIUM/LOW","generated_at":"${new Date().toISOString()}"}  `;

return [{json: {_needsAI: true, prompt, row_data: {id: row.id, opp_title: row.opp_title, agency: row.agency, naics_code: row.naics_code, estimated_value: row.estimated_value, gda_score: row.gda_score}}}];

const resp = $input.first().json;
// If AI Incumbent Analysis short-circuited with DB data
if (resp.status === 'ok') return [{json: resp}];
// Claude response - parse JSON
try {
  const text = resp.content[0].text;
  const clean = text.replace(/```json|```/g,'').trim();
  const s = clean.indexOf('{'); const e = clean.lastIndexOf('}');
  const parsed = JSON.parse(clean.substring(s, e+1));
  parsed.source = 'ai_generated';
  return [{json: parsed}];
} catch(err) {
  return [{json: {status:'ok', source:'ai_fallback', opp_title: 'Unknown', agency: '', likely_incumbents: [{name: 'Unknown', rationale: 'Insufficient data', threat_level: 'MEDIUM'}], weakness_assessment: ['Analysis unavailable'], displacement_strategy: 'Manual research required', win_themes: ['Technical excellence', 'Past performance'], risk_factors: ['Insufficient data'], capture_recommendation: 'Contact capture team for manual assessment', confidence: 'LOW', error: err.message, generated_at: new Date().toISOString()}}];
}
